import{_ as i,c as n,o as t,$ as a}from"./chunks/framework.ByJNblvT.js";const m=JSON.parse('{"title":"🏝️ Environment","description":"","frontmatter":{},"headers":[],"relativePath":"en-US/guide/environment.md","filePath":"en-US/guide/environment.md","lastUpdated":1774623019000}'),o={name:"en-US/guide/environment.md"};function r(l,e,s,d,c,h){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="🏝️-environment" tabindex="-1">🏝️ Environment <a class="header-anchor" href="#🏝️-environment" aria-label="Permalink to “🏝️ Environment”">​</a></h1><h2 id="recommended-environment" tabindex="-1">Recommended environment <a class="header-anchor" href="#recommended-environment" aria-label="Permalink to “Recommended environment”">​</a></h2><p>It is recommended to use the library in modern browsers together with package managers such as <code>npm</code>, <code>pnpm</code>, <code>yarn</code>, or <code>bun</code>.</p><p>If you are integrating it into a production project, it is recommended to:</p><ul><li>Use an ESM-based build tool, such as Vite, Rspack, Webpack, or Rollup</li><li>Initialize the chart after the client component has mounted</li><li>Install it through a package manager instead of depending on a CDN script directly</li></ul><h2 id="browser-support" tabindex="-1">Browser support <a class="header-anchor" href="#browser-support" aria-label="Permalink to “Browser support”">​</a></h2><p>The chart is built on HTML5 Canvas, so it needs to run in a browser that supports Canvas. If you need to run it on mobile, use a modern WebView.</p><p>For modern desktop and mobile browsers, it will usually run directly. If your project needs to support older environments, it is recommended to verify at least the following capabilities:</p><ul><li><code>Map</code></li><li><code>Intl</code></li><li><code>requestAnimationFrame</code></li><li>Canvas-related APIs</li></ul><p>Canvas-related API support is required. <code>Map</code>, <code>Intl</code>, and <code>requestAnimationFrame</code> are common compatibility gaps. If any of them are missing, add the corresponding polyfills yourself.</p><h2 id="ssr-next-js-nuxt-notes" tabindex="-1">SSR / Next.js / Nuxt notes <a class="header-anchor" href="#ssr-next-js-nuxt-notes" aria-label="Permalink to “SSR / Next.js / Nuxt notes”">​</a></h2><p>The chart depends on the DOM and Canvas, so it cannot be initialized directly during server-side rendering.</p><p>Recommended practices:</p><ul><li>Call <code>init(...)</code> only after the component has mounted</li><li>Do not read the container DOM at the module top level</li><li>If the page is shown on demand, initialize only after the container is actually visible, or call <code>resize(...)</code> proactively</li></ul><h2 id="container-size-and-initialization-timing" tabindex="-1">Container size and initialization timing <a class="header-anchor" href="#container-size-and-initialization-timing" aria-label="Permalink to “Container size and initialization timing”">​</a></h2><p>The chart fills its container automatically, so the container itself must have an explicit size.</p><p>Common recommendations:</p><ul><li>The container needs a definite height</li><li>If the width comes from a responsive parent container, make sure the parent layout has stabilized</li><li>If the container is initially <code>display: none</code> or inside an inactive tab, it is recommended to call <code>resize(...)</code> after it becomes visible</li></ul><p>If you can only see a single line after initialization, or the chart height looks wrong, check the container size first.</p><h2 id="high-dpi-screens-and-clarity" tabindex="-1">High-DPI screens and clarity <a class="header-anchor" href="#high-dpi-screens-and-clarity" aria-label="Permalink to “High-DPI screens and clarity”">​</a></h2><p>If the chart looks blurry on high-resolution screens, first check whether extra CSS scaling has been applied to the chart container.</p><p>Recommended:</p><ul><li>Avoid using <code>transform: scale(...)</code> on the chart container</li><li>Avoid wrapping the chart with an extra blurred scaling container</li><li>Call <code>resize(...)</code> promptly after size changes</li></ul><h2 id="mobile-webview-notes" tabindex="-1">Mobile WebView notes <a class="header-anchor" href="#mobile-webview-notes" aria-label="Permalink to “Mobile WebView notes”">​</a></h2><p>When using it on mobile, it is recommended to run it in a newer WebView environment whenever possible.</p><p>During integration, you usually need to pay attention to:</p><ul><li>Whether page scrolling conflicts with chart dragging</li><li>Whether the parent container intercepts touch events</li><li>Whether <code>resize(...)</code> needs to be called again after the keyboard opens or after orientation changes</li><li>Whether styles and tooltip display need adjustment to match mobile interaction habits</li></ul>',27)])])}const u=i(o,[["render",r]]);export{m as __pageData,u as default};
